function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

const execution_context = parseMaybeJson($json.execution_context, {});
const context_packet = parseMaybeJson($json.context_packet, {});
const decision = parseMaybeJson($json.decision, {});
const state_update = parseMaybeJson($json.state_update, {});
const execution_meta = parseMaybeJson($json.execution_meta, {});

const lead_id =
  $json.lead_id ||
  execution_context.lead_id ||
  context_packet?.lead?.id ||
  null;

const channel =
  $json.channel ||
  execution_context.channel ||
  context_packet?.lead?.channel ||
  "whatsapp";

const phone =
  $json.phone ||
  execution_context.phone ||
  context_packet?.lead?.phone ||
  null;

const calendar_id =
  $json.calendar_id ||
  execution_context.calendar_id ||
  null;

const cancellation_reason =
  $json.cancellation_reason ||
  execution_context.cancellation_reason ||
  decision.cancellation_reason ||
  decision.reason ||
  "cancelled_by_client";

if (!lead_id) {
  throw new Error("Missing lead_id in cancel_booking");
}

return [
  {
    json: {
      lead_id,
      channel,
      phone,
      calendar_id,
      cancellation_reason,

      execution_context: {
        ...execution_context,
        lead_id,
        channel,
        phone,
        calendar_id,
        cancellation_reason,
        action: "cancel_booking"
      },

      context_packet,
      decision,
      state_update,
      execution_meta,

      notes: ["cancel_booking_input_normalized"]
    }
  }
];

return [
  {
    json: {
      ...$json,
      success: true,
      action: "cancel_booking",
      message_to_send:
        "No encontr� una reserva activa a tu nombre. Si quieres, puedo ayudarte a agendar una nueva.",
      db_operations: ["messages", "lead_state"],
      state_update: {
        ...($json.state_update || {}),
        last_bot_action: "cancel_booking_no_active_appointment",
        next_goal: "offer_booking",
        missing_fields: []
      },
      execution_result: {
        success: true,
        action: "cancel_booking",
        message_sent: false,
        state_updated: true,
        db_records_created: ["messages", "lead_state"],
        notes: ["cancel_booking_no_active_appointment"]
      },
      notes: [...($json.notes || []), "cancel_booking_no_active_appointment"]
    }
  }
];

const eventId = $json.event_id || $json.appointment?.event_id || null;

return [
  {
    json: {
      ...$json,
      success: true,
      action: "cancel_booking",

      message_to_send:
        "Listo, dej� cancelada tu reserva. Si m�s adelante quieres reagendar, me escribes y revisamos un nuevo horario.",

      db_operations: ["appointments", "followups", "messages", "lead_state"],

      state_update: {
        ...($json.state_update || {}),
        stage: "cancelled",
        next_goal: "reactivate_later",
        last_bot_action: "cancel_booking",
        cancellation_reason:
          $json.execution_context?.cancellation_reason || "cancelled_by_client",
        last_appointment_event_id: eventId,
        missing_fields: []
      },

      execution_result: {
        success: true,
        action: "cancel_booking",
        message_sent: false,
        state_updated: true,
        db_records_created: ["appointments", "followups", "messages", "lead_state"],
        notes: [
          "booking_cancelled",
          eventId ? `event_id:${eventId}` : "event_id_missing"
        ]
      },

      notes: [...($json.notes || []), "booking_cancelled"]
    }
  }
];

const original = (() => {
  try {
    return $("cancel_booking").first().json;
  } catch {
    return {};
  }
})();

const data = {
  ...original,
  ...$json,
  execution_context: {
    ...(original.execution_context || {}),
    ...($json.execution_context || {})
  },
  context_packet: $json.context_packet || original.context_packet || {},
  decision: $json.decision || original.decision || {}
};

const outcome =
  data.outcome ||
  data.execution_result?.outcome ||
  data.result?.outcome ||
  (
    data.active_appointment_found === false ||
    data.active_appointment === null ||
    data.appointment === null
      ? "no_active_appointment"
      : "active_appointment_found"
  );

const finalMessage =
  data.message_to_send ||
  data.message ||
  (
    outcome === "no_active_appointment"
      ? "Revisé y no encontré una reserva activa asociada a este número. Si quieres, te puedo ayudar a agendar una nueva hora."
      : "Listo, dejé cancelada tu reserva. Si más adelante quieres reagendar, te puedo ayudar por aquí."
  );

return [{
  ...data,

  action: "cancel_booking",
  outcome,

  message_to_send: finalMessage,
  message: finalMessage,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...(data.state_update || {}),
    stage: outcome === "active_appointment_found"
      ? "cancelled"
      : data.context_packet?.state?.stage,
    intent_last: outcome,
    next_goal: outcome === "no_active_appointment"
      ? "clarify_or_book"
      : "reactivation",
    last_bot_action: outcome === "no_active_appointment"
      ? "cancel_no_active_appointment"
      : "cancel_booking",
    missing_fields: []
  },

  execution_result: {
    ...(data.execution_result || {}),
    success: true,
    action: "cancel_booking",
    outcome,
    bot: finalMessage
  },

  notes: [
    ...(data.notes || []),
    `cancel_booking_outcome_${outcome}`
  ]
}];

